-- NJ Real Estate Analyzer — SQLite Schema
-- Generated by notebooks/01-cleaning.ipynb
-- Source: Redfin Data Center, Zillow Research, US Census Bureau ACS 5-year (2022)

-- ==========================================
-- Table: redfin_monthly
-- Quarterly market data per ZIP from Redfin.
-- Granularity: rolling 90-day windows, "All Residential" property type only.
-- 676 rows (~170/zip), 4 zips, 2012 → 2026
-- ==========================================
-- zip                 TEXT   -- 5-digit ZIP code
-- period_begin        DATE   -- start of 90-day window
-- period_end          DATE   -- end of 90-day window
-- period_days         INT    -- always 90
-- median_sale_price   FLOAT  -- dollars
-- median_ppsf         FLOAT  -- price per square foot
-- homes_sold          INT
-- new_listings        FLOAT
-- inventory           FLOAT
-- median_dom          FLOAT  -- median days on market
-- months_of_supply    FLOAT  -- inventory ÷ sales velocity
-- pending_sales       FLOAT
-- median_list_price   FLOAT

-- ==========================================
-- Table: zhvi_monthly
-- Zillow Home Value Index — smoothed monthly estimate of typical home value.
-- 1,256 rows, 4 zips, 2000-01 → 2026-02
-- ==========================================
-- zip    TEXT
-- month  DATE    -- month-end date
-- zhvi   FLOAT   -- dollars

-- ==========================================
-- Table: zori_monthly
-- Zillow Observed Rent Index — smoothed monthly rent estimate.
-- 75 rows, 3 zips (08534 Pennington has no coverage), 2022-01 → 2026-02
-- ==========================================
-- zip    TEXT
-- month  DATE
-- zori   FLOAT   -- dollars/month

-- ==========================================
-- Table: demographics
-- Census ACS 5-year 2022 estimates, one row per ZIP.
-- ==========================================
-- zip                      TEXT
-- population               INT
-- median_hh_income         INT     -- dollars/year
-- median_age               FLOAT   -- years
-- total_housing_units      INT
-- owner_occupied_units     INT
-- median_home_value        INT     -- dollars, Census estimate
-- median_gross_rent        INT     -- dollars/month
-- bachelors_degree_holders INT
-- pct_owner_occupied       FLOAT   -- derived: owner/total, rounded to 3 dp

-- ==========================================
-- Table: taxes
-- Census ACS 5-year 2022 estimates, property tax facts per ZIP.
-- Note: Census top-codes at $10,001 for privacy — see taxes_topcoded flag.
-- ==========================================
-- zip                          TEXT
-- median_real_estate_taxes     INT     -- annual dollars, topcoded at 10001
-- median_monthly_owner_costs   INT     -- includes mortgage, tax, insurance
-- median_home_value            INT     -- dollars
-- effective_tax_rate_pct       FLOAT   -- derived: taxes/value * 100, percent
-- taxes_topcoded               BOOLEAN -- True if taxes == 10001 (actual ≥ 10001)
